class Solution {
    public int[] popcountDepth(long[] nums, long[][] queries) {
        int[] answer = new int[queries.length];
        for (int i = 0; i < queries.length; i++) {
            if (queries[i].length == 3) {
                int idx = (int) queries[i][0];
                long val = queries[i][1];
                nums[idx] = val;
            } else {
                int l = (int) queries[i][0];
                int r = (int) queries[i][1];
                int k = (int) queries[i][2];
                int count = 0;
                for (int j = l; j <= r; j++) {
                    if (popcountDepth(nums[j]) == k) {
                        count++;
                    }
                }
                answer[i] = count;
            }
        }
        return answer;
    }
    private int popcountDepth(long num) {
        int count = 0;
        while (num > 0) {
            count += num & 1;
            num >>= 1;
        }
        return count;
    }
}
